sys_ws_operation.operation_script:
(function process(request, response) {
  var utils = new AlationUtils();



  var qp     = request.queryParams || {};
  var sysId  = (qp.sys_id || qp.id || '').toString().trim();
  var number = (qp.number || '').toString().trim();
  var extId  = (qp.externalIncidentId || qp.external_id || '').toString().trim();

  if (!sysId && !number && !extId) {
    var body = utils.readJsonOnce(request) || {};
    sysId  = (body.sys_id || body.id || '').toString().trim();
    number = (body.number || '').toString().trim();
    extId  = (body.externalIncidentId || body.external_id || '').toString().trim();
  }

  var inc = new GlideRecord('incident');
  var found = false;

  if (sysId && inc.get(sysId)) {
    found = true;
  } else if (number) {
    inc.addQuery('number', number);
    inc.setLimit(1); inc.query();
    if (inc.next()) found = true;
  } else if (extId) {
    inc.addQuery('correlation_id', extId);
    inc.setLimit(1); inc.query();
    if (inc.next()) found = true;
  }

  if (!found) return utils.error(response, 404, 'incident not found');

  var businessSeconds = null;
  try {
    var dur = inc.business_duration;
    if (dur && dur.getNumericValue) {
      businessSeconds = Math.floor(dur.getNumericValue() / 1000);
    } else {
      var raw = String(inc.getValue('business_duration') || '');
      var n = parseInt(raw, 10);
      businessSeconds = isNaN(n) ? null : n;
    }
  } catch (e) {
    businessSeconds = null;
  }

  var assignee = null;
  try {
    var hasAssignee = String(inc.assigned_to || '') !== '';
    if (hasAssignee) {
      var usr = null;
      var assigneeId = String(inc.getValue('assigned_to') || '');
      if (assigneeId) {
        usr = inc.assigned_to.getRefRecord();
        if (!(usr && usr.isValidRecord && usr.isValidRecord())) {
          usr = null;
		}
      }
      if (usr && usr.isValidRecord && usr.isValidRecord()) {
        assignee = {
          account_id: String(usr.sys_id),
          display_name: String(usr.name || inc.getDisplayValue('assigned_to') || ''),
          user_name: String(usr.user_name || ''),
          email: String(usr.email || '')
        };
      } else {
        assignee = {
          account_id: String(inc.assigned_to),
          display_name: String(inc.getDisplayValue('assigned_to') || '')
        };
      }
    }
  } catch (ignore) {}

  // --- Assignment group object {account_id, display_name} ---
  var assignmentGroup = null;
  try {
    var hasGrp = String(inc.assignment_group || '') !== '';
    if (hasGrp) {
      var grp = null;
      var grpId = String(inc.getValue('assignment_group') || '');
      if (grpId) {
        grp = inc.assignment_group.getRefRecord();
        if (!(grp && grp.isValidRecord && grp.isValidRecord())) {
          grp = null;
        }
      }
      if (grp && grp.isValidRecord && grp.isValidRecord()) {
        assignmentGroup = {
          account_id: String(grp.sys_id),
          display_name: String(grp.name || inc.getDisplayValue('assignment_group') || '')
        };
      } else {
        assignmentGroup = {
          account_id: String(inc.assignment_group),
          display_name: String(inc.getDisplayValue('assignment_group') || '')
        };
      }
    }
  } catch (ignore) {}

  var priorityObj = {
      value: String(inc.getValue('priority')),
      display_value: inc.getDisplayValue('priority')
    };

  var payload = {
    sys_id: String(inc.sys_id),
    number: String(inc.number),

    external_incident_id: String(inc.correlation_id || ''),

    short_description: String(inc.short_description || ''),
    description: String(inc.description || ''),

    impact: String(inc.impact),
    impact_label: inc.getDisplayValue('impact'),
    urgency: String(inc.urgency),
    urgency_label: inc.getDisplayValue('urgency'),

    category: String(inc.category || ''),
    category_label: inc.getDisplayValue('category'),
    subcategory: String(inc.subcategory || ''),
    subcategory_label: inc.getDisplayValue('subcategory'),

    priority: priorityObj,

    state: String(inc.state),
    state_label: inc.getDisplayValue('state'),

    opened_at: String(inc.opened_at || ''),
    closed_at: String(inc.closed_at || ''),
    sys_created_on: String(inc.sys_created_on || ''),
    sys_updated_on: String(inc.sys_updated_on || ''),

    business_elapsed_seconds: businessSeconds,
    business_elapsed_display: inc.getDisplayValue('business_duration'),

    assignee: assignee,
    assignment_group: assignmentGroup,

    url: utils.incidentUrl(String(inc.sys_id))
  };
  return utils.ok(response, 200, payload);

})(request, response);
